using ModelContextProtocol.Server;

var builder = WebApplication.CreateBuilder(args);

builder.Services
    .AddMcpServer()
    .WithHttpTransport()
    .WithTools<MyTools>()
    .WithResources<MyResources>();

var app = builder.Build();

app.MapMcp();

app.Run();

// ── Tools ───────────────────────────────────────────────────────────────────

[McpServerToolType]
public static class MyTools
{
    [McpServerTool(Name = "echo", Title = "Echo")]
    public static string Echo(string message) => $"Echo: {message}";

    [McpServerTool(Name = "add", Title = "Add Numbers")]
    public static string Add(double a, double b) => $"Result: {a + b}";
}

// ── Resources ───────────────────────────────────────────────────────────────

[McpServerResourceType]
public static class MyResources
{
    [McpServerResource(UriTemplate = "config://app", Name = "app-config",
        Title = "Application Configuration", MimeType = "application/json")]
    public static string GetAppConfig() =>
        """
        {
          "appName": "McpHttpServer",
          "version": "1.0.0",
          "features": { "logging": true, "metrics": false }
        }
        """;

    [McpServerResource(UriTemplate = "config://env/{name}", Name = "env-var",
        Title = "Environment Variable", MimeType = "text/plain")]
    public static string GetEnvVar(string name) =>
        Environment.GetEnvironmentVariable(name) ?? $"(not set: {name})";
}

